// DApp Backend Service - Ethereum Blockchain Interaction
// Uses ethers.js for Ethereum blockchain interaction with secure key management

const { ethers } = require('ethers');
const crypto = require('crypto');
const fs = require('fs');
const path = require('path');

// ============================================================
// Secure Key Management Module
// ============================================================

class SecureKeyManager {
  constructor() {
    // Derive encryption key from environment variable (set via secure secret manager)
    // In production, use AWS KMS, HashiCorp Vault, Azure Key Vault, or GCP Secret Manager
    const masterSecret = process.env.WALLET_MASTER_SECRET;
    if (!masterSecret) {
      throw new Error(
        'WALLET_MASTER_SECRET environment variable is not set. ' +
        'Set it via your platform secret manager (AWS Secrets Manager, HashiCorp Vault, etc.)'
      );
    }
    this._encryptionKey = crypto.scryptSync(masterSecret, 'dapp-backend-salt', 32);
  }

  // Encrypt a private key before storing it
  encryptPrivateKey(privateKey) {
    const iv = crypto.randomBytes(16);
    const cipher = crypto.createCipheriv('aes-256-gcm', this._encryptionKey, iv);
    let encrypted = cipher.update(privateKey, 'utf8', 'hex');
    encrypted += cipher.final('hex');
    const authTag = cipher.getAuthTag().toString('hex');
    return {
      iv: iv.toString('hex'),
      encryptedData: encrypted,
      authTag: authTag
    };
  }

  // Decrypt a private key for signing (kept in memory only briefly)
  decryptPrivateKey(encryptedPayload) {
    const { iv, encryptedData, authTag } = encryptedPayload;
    const decipher = crypto.createDecipheriv(
      'aes-256-gcm',
      this._encryptionKey,
      Buffer.from(iv, 'hex')
    );
    decipher.setAuthTag(Buffer.from(authTag, 'hex'));
    let decrypted = decipher.update(encryptedData, 'hex', 'utf8');
    decrypted += decipher.final('utf8');
    return decrypted;
  }

  // Store encrypted keystore to file (for demonstration; use a database or vault in production)
  saveEncryptedKeystore(walletName, encryptedPayload) {
    const keystorePath = path.join(__dirname, '.keystore');
    if (!fs.existsSync(keystorePath)) {
      fs.mkdirSync(keystorePath, { mode: 0o700 });
    }
    const filePath = path.join(keystorePath, `${walletName}.json`);
    fs.writeFileSync(filePath, JSON.stringify(encryptedPayload), { mode: 0o600 });
    console.log(`Encrypted keystore saved for wallet: ${walletName}`);
  }

  // Load encrypted keystore from file
  loadEncryptedKeystore(walletName) {
    const filePath = path.join(__dirname, '.keystore', `${walletName}.json`);
    if (!fs.existsSync(filePath)) {
      throw new Error(`Keystore not found for wallet: ${walletName}`);
    }
    const data = fs.readFileSync(filePath, 'utf8');
    return JSON.parse(data);
  }

  // Create a temporary signer that cleans up after use
  async withSigner(provider, walletName, callback) {
    let privateKey = null;
    try {
      const encryptedPayload = this.loadEncryptedKeystore(walletName);
      privateKey = this.decryptPrivateKey(encryptedPayload);
      const wallet = new ethers.Wallet(privateKey, provider);
      const result = await callback(wallet);
      return result;
    } finally {
      // Clear the private key from memory
      if (privateKey) {
        privateKey = null;
      }
    }
  }
}

// ============================================================
// Ethereum Service Module
// ============================================================

class EthereumService {
  constructor(config = {}) {
    // Provider configuration - use environment variables
    const rpcUrl = config.rpcUrl || process.env.ETH_RPC_URL || 'http://localhost:8545';
    this.provider = new ethers.JsonRpcProvider(rpcUrl);
    this.keyManager = new SecureKeyManager();
    this.chainId = config.chainId || parseInt(process.env.ETH_CHAIN_ID || '1');

    console.log(`Ethereum service initialized. RPC: ${rpcUrl}, Chain ID: ${this.chainId}`);
  }

  // --------------------------------------------------------
  // Wallet Management
  // --------------------------------------------------------

  // Register a new wallet by encrypting and storing its private key
  registerWallet(walletName, privateKey) {
    // Validate the private key format
    try {
      const tempWallet = new ethers.Wallet(privateKey);
      console.log(`Registering wallet "${walletName}" with address: ${tempWallet.address}`);
    } catch (err) {
      throw new Error('Invalid private key format');
    }

    const encryptedPayload = this.keyManager.encryptPrivateKey(privateKey);
    this.keyManager.saveEncryptedKeystore(walletName, encryptedPayload);

    // Never log or return the private key
    return { walletName, status: 'registered' };
  }

  // Generate a new wallet, encrypt and store it
  generateAndRegisterWallet(walletName) {
    const wallet = ethers.Wallet.createRandom();
    const encryptedPayload = this.keyManager.encryptPrivateKey(wallet.privateKey);
    this.keyManager.saveEncryptedKeystore(walletName, encryptedPayload);

    console.log(`Generated and registered wallet "${walletName}" with address: ${wallet.address}`);

    // Return only the address, never the private key
    return {
      walletName,
      address: wallet.address,
      status: 'generated_and_registered'
    };
  }

  // Get wallet address without exposing private key
  async getWalletAddress(walletName) {
    return await this.keyManager.withSigner(this.provider, walletName, async (wallet) => {
      return wallet.address;
    });
  }

  // --------------------------------------------------------
  // ETH Transactions
  // --------------------------------------------------------

  // Get ETH balance for an address
  async getBalance(address) {
    const balance = await this.provider.getBalance(address);
    return {
      wei: balance.toString(),
      ether: ethers.formatEther(balance)
    };
  }

  // Send ETH from a registered wallet to a recipient
  async sendETH(fromWalletName, toAddress, amountInEther, options = {}) {
    return await this.keyManager.withSigner(this.provider, fromWalletName, async (wallet) => {
      console.log(`Sending ${amountInEther} ETH from ${wallet.address} to ${toAddress}`);

      // Build transaction
      const tx = {
        to: toAddress,
        value: ethers.parseEther(amountInEther.toString()),
        chainId: this.chainId
      };

      // Optional gas configuration
      if (options.gasLimit) {
        tx.gasLimit = options.gasLimit;
      }
      if (options.maxFeePerGas) {
        tx.maxFeePerGas = ethers.parseUnits(options.maxFeePerGas.toString(), 'gwei');
      }
      if (options.maxPriorityFeePerGas) {
        tx.maxPriorityFeePerGas = ethers.parseUnits(options.maxPriorityFeePerGas.toString(), 'gwei');
      }
      if (options.nonce !== undefined) {
        tx.nonce = options.nonce;
      }

      // Sign and send
      const txResponse = await wallet.sendTransaction(tx);
      console.log(`Transaction sent. Hash: ${txResponse.hash}`);

      // Optionally wait for confirmation
      if (options.waitConfirmations) {
        const receipt = await txResponse.wait(options.waitConfirmations);
        console.log(`Transaction confirmed in block: ${receipt.blockNumber}`);
        return {
          hash: txResponse.hash,
          blockNumber: receipt.blockNumber,
          gasUsed: receipt.gasUsed.toString(),
          status: receipt.status === 1 ? 'success' : 'failed'
        };
      }

      return {
        hash: txResponse.hash,
        status: 'pending'
      };
    });
  }

  // --------------------------------------------------------
  // Smart Contract Interaction
  // --------------------------------------------------------

  // Create a contract instance for read-only operations
  getContract(contractAddress, abi) {
    return new ethers.Contract(contractAddress, abi, this.provider);
  }

  // Read from a smart contract (no signing needed)
  async readContract(contractAddress, abi, methodName, args = []) {
    const contract = this.getContract(contractAddress, abi);

    if (typeof contract[methodName] !== 'function') {
      throw new Error(`Method "${methodName}" not found on contract`);
    }

    const result = await contract[methodName](...args);
    console.log(`Contract read: ${methodName}() => ${result}`);
    return result;
  }

  // Write to a smart contract (requires signing)
  async writeContract(walletName, contractAddress, abi, methodName, args = [], options = {}) {
    return await this.keyManager.withSigner(this.provider, walletName, async (wallet) => {
      const contract = new ethers.Contract(contractAddress, abi, wallet);

      if (typeof contract[methodName] !== 'function') {
        throw new Error(`Method "${methodName}" not found on contract`);
      }

      console.log(`Contract write: ${methodName}(${args.join(', ')}) from ${wallet.address}`);

      // Build overrides
      const overrides = {};
      if (options.gasLimit) overrides.gasLimit = options.gasLimit;
      if (options.value) overrides.value = ethers.parseEther(options.value.toString());
      if (options.maxFeePerGas) {
        overrides.maxFeePerGas = ethers.parseUnits(options.maxFeePerGas.toString(), 'gwei');
      }
      if (options.maxPriorityFeePerGas) {
        overrides.maxPriorityFeePerGas = ethers.parseUnits(options.maxPriorityFeePerGas.toString(), 'gwei');
      }

      const txResponse = await contract[methodName](...args, overrides);
      console.log(`Transaction sent. Hash: ${txResponse.hash}`);

      if (options.waitConfirmations) {
        const receipt = await txResponse.wait(options.waitConfirmations);
        console.log(`Transaction confirmed in block: ${receipt.blockNumber}`);
        return {
          hash: txResponse.hash,
          blockNumber: receipt.blockNumber,
          gasUsed: receipt.gasUsed.toString(),
          status: receipt.status === 1 ? 'success' : 'failed',
          events: receipt.logs
        };
      }

      return {
        hash: txResponse.hash,
        status: 'pending'
      };
    });
  }

  // Deploy a smart contract
  async deployContract(walletName, abi, bytecode, constructorArgs = [], options = {}) {
    return await this.keyManager.withSigner(this.provider, walletName, async (wallet) => {
      console.log(`Deploying contract from ${wallet.address}`);

      const factory = new ethers.ContractFactory(abi, bytecode, wallet);

      const overrides = {};
      if (options.gasLimit) overrides.gasLimit = options.gasLimit;
      if (options.value) overrides.value = ethers.parseEther(options.value.toString());

      const contract = await factory.deploy(...constructorArgs, overrides);
      await contract.waitForDeployment();

      const deployedAddress = await contract.getAddress();
      console.log(`Contract deployed at: ${deployedAddress}`);

      return {
        address: deployedAddress,
        deployTransaction: contract.deploymentTransaction()?.hash
      };
    });
  }

  // --------------------------------------------------------
  // ERC-20 Token Helpers
  // --------------------------------------------------------

  // Standard ERC-20 ABI (minimal)
  static get ERC20_ABI() {
    return [
      'function name() view returns (string)',
      'function symbol() view returns (string)',
      'function decimals() view returns (uint8)',
      'function totalSupply() view returns (uint256)',
      'function balanceOf(address owner) view returns (uint256)',
      'function transfer(address to, uint256 amount) returns (bool)',
      'function approve(address spender, uint256 amount) returns (bool)',
      'function allowance(address owner, address spender) view returns (uint256)',
      'function transferFrom(address from, address to, uint256 amount) returns (bool)',
      'event Transfer(address indexed from, address indexed to, uint256 value)',
      'event Approval(address indexed owner, address indexed spender, uint256 value)'
    ];
  }

  // Get ERC-20 token balance
  async getTokenBalance(tokenAddress, ownerAddress) {
    const contract = this.getContract(tokenAddress, EthereumService.ERC20_ABI);
    const [balance, decimals, symbol] = await Promise.all([
      contract.balanceOf(ownerAddress),
      contract.decimals(),
      contract.symbol()
    ]);

    return {
      raw: balance.toString(),
      formatted: ethers.formatUnits(balance, decimals),
      symbol,
      decimals
    };
  }

  // Transfer ERC-20 tokens
  async transferToken(walletName, tokenAddress, toAddress, amount, options = {}) {
    const contract = this.getContract(tokenAddress, EthereumService.ERC20_ABI);
    const decimals = await contract.decimals();
    const parsedAmount = ethers.parseUnits(amount.toString(), decimals);

    return await this.writeContract(
      walletName,
      tokenAddress,
      EthereumService.ERC20_ABI,
      'transfer',
      [toAddress, parsedAmount],
      options
    );
  }

  // --------------------------------------------------------
  // Utility Functions
  // --------------------------------------------------------

  // Estimate gas for a transaction
  async estimateGas(tx) {
    const gasEstimate = await this.provider.estimateGas(tx);
    return gasEstimate.toString();
  }

  // Get current gas price
  async getGasPrice() {
    const feeData = await this.provider.getFeeData();
    return {
      gasPrice: feeData.gasPrice?.toString(),
      maxFeePerGas: feeData.maxFeePerGas?.toString(),
      maxPriorityFeePerGas: feeData.maxPriorityFeePerGas?.toString()
    };
  }

  // Get transaction receipt
  async getTransactionReceipt(txHash) {
    return await this.provider.getTransactionReceipt(txHash);
  }

  // Listen for contract events
  listenToEvent(contractAddress, abi, eventName, callback) {
    const contract = this.getContract(contractAddress, abi);
    contract.on(eventName, (...args) => {
      const event = args[args.length - 1]; // Last argument is the event object
      callback(event, args.slice(0, -1));
    });
    console.log(`Listening for "${eventName}" events on ${contractAddress}`);

    // Return unsubscribe function
    return () => {
      contract.off(eventName);
      console.log(`Stopped listening for "${eventName}" events`);
    };
  }

  // Get block number
  async getBlockNumber() {
    return await this.provider.getBlockNumber();
  }

  // Get network info
  async getNetwork() {
    const network = await this.provider.getNetwork();
    return {
      name: network.name,
      chainId: network.chainId.toString()
    };
  }
}

